{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_pretooluse_guard.py\"",
            "timeout": 10,
            "statusMessage": "CC10X protected-write guard"
          }
        ]
      },
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_git_guard.py\"",
            "timeout": 5,
            "statusMessage": "CC10X git guardrails"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "matcher": "startup|resume|compact",
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_sessionstart_context.py\"",
            "timeout": 10,
            "statusMessage": "CC10X workflow resume context"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_posttooluse_artifact_guard.py\"",
            "timeout": 10,
            "statusMessage": "CC10X workflow artifact audit"
          }
        ]
      }
    ],
    "TaskCompleted": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_task_completed_guard.py\"",
            "timeout": 10,
            "statusMessage": "CC10X task metadata guard"
          }
        ]
      }
    ],
    "PostCompact": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_event_logger.py\" postcompact",
            "timeout": 10,
            "statusMessage": "CC10X compaction event capture"
          }
        ]
      }
    ],
    "SubagentStop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_event_logger.py\" subagent_stop",
            "timeout": 10,
            "statusMessage": "CC10X subagent contract audit"
          }
        ]
      }
    ],
    "PreCompact": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_state_persist.py\" precompact",
            "timeout": 5,
            "statusMessage": "CC10X pre-compaction state snapshot"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_state_persist.py\" stop",
            "timeout": 3,
            "statusMessage": "CC10X session state persistence"
          }
        ]
      }
    ],
    "StopFailure": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_event_logger.py\" stop_failure",
            "timeout": 3,
            "async": true,
            "statusMessage": "CC10X failure event logging"
          }
        ]
      }
    ],
    "InstructionsLoaded": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/scripts/cc10x_event_logger.py\" instructions_loaded",
            "timeout": 5,
            "async": true,
            "statusMessage": "CC10X instruction audit"
          }
        ]
      }
    ]
  }
}

